══════════════════════════════════════════ */
(function startClock() {
  const el = document.getElementById('clock');
  function tick() {
    const n = new Date();
    el.textContent =
      n.toLocaleDateString('en-US', {weekday:'short', month:'short', day:'numeric'}) +
      '  ' +
      n.toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'});
  }
  tick();
  setInterval(tick, 5000);
})();

/* ══════════════════════════════════════════
   Window management
══════════════════════════════════════════ */
let z = 200;

function bringUp(win) { win.style.zIndex = ++z; }

function showWin(id) {
  const w = document.getElementById(id);
  w.style.display = 'flex';
  bringUp(w);
}

function hideWin(id) {
  document.getElementById(id).style.display = 'none';
}

// Close buttons
document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', () => hideWin(btn.dataset.win));
});

// Raise on mousedown
document.querySelectorAll('.window').forEach(w => {
  w.addEventListener('mousedown', () => bringUp(w));
});

// Launchers
document.getElementById('open-files').addEventListener('click', () => {
  showWin('files-window');
  fsRender();
});
document.getElementById('open-notepad').addEventListener('click', () => {
