  tabRender();
});

/* ══════════════════════════════════════════
   Drag
══════════════════════════════════════════ */
document.querySelectorAll('.win-titlebar').forEach(bar => {
  const win = bar.closest('.window');
  let dragging = false, ox = 0, oy = 0;

  bar.addEventListener('mousedown', e => {
    if (e.target.tagName === 'BUTTON') return;
    dragging = true;
    const r = win.getBoundingClientRect();
    ox = e.clientX - r.left;
    oy = e.clientY - r.top;
    bringUp(win);
    e.preventDefault();
  });
  document.addEventListener('mousemove', e => {
    if (!dragging) return;
    win.style.left = Math.max(0, Math.min(e.clientX - ox, innerWidth  - win.offsetWidth))  + 'px';
    win.style.top  = Math.max(30, Math.min(e.clientY - oy, innerHeight - win.offsetHeight)) + 'px';
  });
  document.addEventListener('mouseup', () => { dragging = false; });
});

