function isDir(p) { return Object.prototype.hasOwnProperty.call(FS, p); }

const EXT_ICONS = {
  '.txt':'📄', '.md':'📄', '.ini':'📄', '.conf':'📄', '.cfg':'📄',
  '.log':'📋', '.dat':'📋',
  '.pdf':'📕',
  '.png':'🖼️', '.jpg':'🖼️', '.jpeg':'🖼️', '.gif':'🖼️',
  '.tar.gz':'📦', '.gz':'📦', '.zip':'📦', '.deb':'📦', '.tar':'📦', '.xz':'📦',
  '.iso':'💿', '.mp4':'🎬', '.mkv':'🎬',
  '.sh':'⚙️', '.desktop':'⚙️',
  '.h':'📎', '.c':'📎', '.so.6':'🔧', '.so':'🔧',
  '.rsa':'🔑', '.pub':'🔑',
  '.ods':'📊',
};

function fileIcon(name, dir) {
  if (dir) return '📁';
  if (name.endsWith('.tar.gz') || name.endsWith('.log.xz') || name.endsWith('.eipp.log.xz')) return '📦';
  const dot = name.indexOf('.');
  if (dot !== -1) {
    // try longest extension first
    for (const ext of Object.keys(EXT_ICONS)) {
      if (name.endsWith(ext)) return EXT_ICONS[ext];
    }
  }
  return '📄';
}

let cwd = '/';

function fsRender() {
  const grid   = document.getElementById('files-grid');
  const pathEl = document.getElementById('files-path');
  const status = document.getElementById('files-statusbar');

  pathEl.textContent = cwd;
  grid.innerHTML = '';

  const node = FS[cwd];
  const children = (node && node.children) ? node.children : [];

  children.forEach(name => {
    const fullPath = (cwd === '/' ? '' : cwd) + '/' + name;
    const dir = isDir(fullPath);

    const item = document.createElement('div');
    item.className = 'fs-item';
    item.innerHTML =
      '<span class="fs-icon">' + fileIcon(name, dir) + '</span>' +
      '<span class="fs-name">' + name + '</span>';

    item.addEventListener('click', e => {
      document.querySelectorAll('.fs-item.selected').forEach(i => i.classList.remove('selected'));
      item.classList.add('selected');
      e.stopPropagation();
    });

    if (dir) {
      item.addEventListener('dblclick', () => {
        cwd = fullPath;
        fsRender();
      });
    }

    grid.appendChild(item);
  });

  const n = children.length;
  status.textContent = n + ' item' + (n !== 1 ? 's' : '');
}

// Deselect on grid background click
document.getElementById('files-grid').addEventListener('click', e => {
  if (e.target.id === 'files-grid')
    document.querySelectorAll('.fs-item.selected').forEach(i => i.classList.remove('selected'));
});

document.getElementById('files-up').addEventListener('click', () => {
  if (cwd === '/') return;
  const parts = cwd.split('/').filter(Boolean);
  parts.pop();
  cwd = parts.length ? '/' + parts.join('/') : '/';
  fsRender();
});

/* ══════════════════════════════════════════
   Notepad — tabbed, localStorage persistent
══════════════════════════════════════════ */
const LS_TABS = 'ntpad_tabs_v3';
const LS_ACT  = 'ntpad_active_v3';

let tabs = [];
let activeId = null;
let seq = 1;

function loadTabs() {
  try {
    const raw = localStorage.getItem(LS_TABS);
    if (raw) {
      tabs = JSON.parse(raw);
      if (tabs.length) seq = Math.max(...tabs.map(t => t.id)) + 1;
    }
  } catch (_) { tabs = []; }

  if (!tabs.length) {
    tabs = [{ id: seq++, label: 'Untitled', content: '' }];
  }

  try {
    const a = parseInt(localStorage.getItem(LS_ACT));
    if (!isNaN(a) && tabs.find(t => t.id === a)) activeId = a;
  } catch (_) {}

  if (activeId === null) activeId = tabs[0].id;
}

function saveTabs() {
  // flush current editor into active tab
  const ed = document.getElementById('editor');
  const cur = tabs.find(t => t.id === activeId);
  if (cur && ed) cur.content = ed.value;
  try {
    localStorage.setItem(LS_TABS, JSON.stringify(tabs));
    localStorage.setItem(LS_ACT,  String(activeId));
  } catch (_) {}
}

function tabRender() {
  const strip = document.getElementById('tabs');
  const ed    = document.getElementById('editor');
  strip.innerHTML = '';

  tabs.forEach(tab => {
    const el = document.createElement('div');
    el.className = 'tab' + (tab.id === activeId ? ' active' : '');
    el.dataset.id = tab.id;

    const lbl = document.createElement('span');
    lbl.className = 'tab-label';
    lbl.textContent = tab.label;

    const x = document.createElement('button');
    x.className = 'tab-x';
    x.innerHTML = '&#215;';
    x.title = 'Close';

    el.appendChild(lbl);
    el.appendChild(x);

    el.addEventListener('click', e => { if (e.target !== x) tabSwitch(tab.id); });
    x.addEventListener('click', e => { e.stopPropagation(); tabClose(tab.id); });

    strip.appendChild(el);
  });

  const active = tabs.find(t => t.id === activeId);
  if (active && ed) {
    ed.value = active.content;
    ed.focus();
  }
}

function tabSwitch(id) {
  const ed = document.getElementById('editor');
  const cur = tabs.find(t => t.id === activeId);
  if (cur && ed) cur.content = ed.value;
  activeId = id;
  saveTabs();
  tabRender();
}

function tabClose(id) {
  if (tabs.length === 1) {
    // Reset rather than close
    tabs[0].content = '';
    tabs[0].label = 'Untitled';
    saveTabs();
    tabRender();
    return;
  }
  const idx = tabs.findIndex(t => t.id === id);
  tabs.splice(idx, 1);
  if (activeId === id) activeId = tabs[Math.min(idx, tabs.length - 1)].id;
  saveTabs();
  tabRender();
}

document.getElementById('new-tab').addEventListener('click', () => {
  const ed = document.getElementById('editor');
  const cur = tabs.find(t => t.id === activeId);
  if (cur && ed) cur.content = ed.value;
  const t = { id: seq++, label: 'Untitled', content: '' };
  tabs.push(t);
  activeId = t.id;
  saveTabs();
  tabRender();
});

document.getElementById('editor').addEventListener('input', () => {
  const ed = document.getElementById('editor');
  const tab = tabs.find(t => t.id === activeId);
  if (!tab) return;
  tab.content = ed.value;

  // derive label from first non-empty line, trimmed, max 22 chars
  const first = ed.value.split('\n').find(l => l.trim()) || '';
  tab.label = first.trim().slice(0, 22) || 'Untitled';

  saveTabs();

  // patch label in strip without full re-render
  const lel = document.querySelector('.tab[data-id="' + activeId + '"] .tab-label');
  if (lel) lel.textContent = tab.label;
});

/* ══════════════════════════════════════════
   Init
══════════════════════════════════════════ */
loadTabs();
fsRender();   // pre-render (window is hidden — harmless)

window.addEventListener('beforeunload', saveTabs);
</script>
